1	import { existsSync, readFileSync, readdirSync, mkdirSync, writeFileSync } from "node:fs";
2	import { join } from "node:path";
3	import { DEFAULT_VAULT_PATH, VAULT_DIRS, VAULT_FILES, VERSION } from "./constants";
4	import { getCairnMdTemplate, INDEX_MD_STUB, LOG_MD_STUB, CONTEXT_MD_STUB } from "./templates";
5	
6	export type VaultState = "empty" | "cairn" | "obsidian" | "occupied";
7	
8	export function resolveVaultPath(projectDir?: string): string {
9	  const envPath = process.env.CAIRN_VAULT;
10	  if (envPath) return envPath;
11	
12	  if (projectDir) {
13	    const dotCairn = join(projectDir, ".cairn");
14	    if (existsSync(dotCairn)) {
15	      try {
16	        const content = readFileSync(dotCairn, "utf-8").trim();
17	        if (content) return content;
18	      } catch {
19	        // Fall through to default
20	      }
21	    }
22	  }
23	
24	  return DEFAULT_VAULT_PATH;
25	}
26	
27	export function checkVaultState(vaultPath: string): VaultState {
28	  if (!existsSync(vaultPath)) return "empty";
29	  if (existsSync(join(vaultPath, ".cairn", "state.json"))) return "cairn";
30	  if (existsSync(join(vaultPath, ".obsidian"))) return "obsidian";
31	  const entries = readdirSync(vaultPath);
32	  if (entries.length === 0) return "empty";
33	  return "occupied";
34	}
35	
36	interface ScaffoldResult {
37	  created: string[];
38	  skipped: string[];
39	}
40	
41	const FILE_CONTENT: Record<string, string> = {
42	  "CAIRN.md": getCairnMdTemplate(),
43	  "index.md": INDEX_MD_STUB,
44	  "log.md": LOG_MD_STUB,
45	  "context.md": CONTEXT_MD_STUB,
46	};
47	
48	export function scaffoldVault(vaultPath: string): ScaffoldResult {
49	  const created: string[] = [];
50	  const skipped: string[] = [];
51	
52	  if (!existsSync(vaultPath)) {
53	    mkdirSync(vaultPath, { recursive: true });
54	    created.push(vaultPath);
55	  }
56	
57	  for (const dir of VAULT_DIRS) {
58	    const dirPath = join(vaultPath, dir);
59	    if (existsSync(dirPath)) {
60	      skipped.push(dir + "/");
61	    } else {
62	      mkdirSync(dirPath, { recursive: true });
63	      created.push(dir + "/");
64	    }
65	  }
66	
67	  for (const file of VAULT_FILES) {
68	    const filePath = join(vaultPath, file);
69	    if (existsSync(filePath)) {
70	      skipped.push(file);
71	    } else {
72	      writeFileSync(filePath, FILE_CONTENT[file]!);
73	      created.push(file);
74	    }
75	  }
76	
77	  const statePath = join(vaultPath, ".cairn", "state.json");
78	  const stateDir = join(vaultPath, ".cairn");
79	  if (existsSync(statePath)) {
80	    skipped.push(".cairn/state.json");
81	  } else {
82	    mkdirSync(stateDir, { recursive: true });
83	    writeFileSync(
84	      statePath,
85	      JSON.stringify(
86	        {
87	          version: VERSION,
88	          vaultPath,
89	          createdAt: new Date().toISOString(),
90	        },
91	        null,
92	        2
93	      )
94	    );
95	    created.push(".cairn/state.json");
96	  }
97	
98	  return { created, skipped };
99	}
