1	import {
2	  closeSync,
3	  mkdirSync,
4	  openSync,
5	  readFileSync,
6	  unlinkSync,
7	  writeSync,
8	} from "node:fs";
9	import { dirname } from "node:path";
10	
11	export interface LockOptions {
12	  staleMs?: number;
13	  retryMs?: number;
14	  retries?: number;
15	}
16	
17	interface LockPayload {
18	  pid: number;
19	  createdAt: string;
20	}
21	
22	const DEFAULTS: Required<LockOptions> = {
23	  staleMs: 5 * 60 * 1000,
24	  retryMs: 100,
25	  retries: 50,
26	};
27	
28	export class LockBusyError extends Error {
29	  constructor(path: string) {
30	    super(`Lock is busy after retry budget exhausted: ${path}`);
31	    this.name = "LockBusyError";
32	  }
33	}
34	
35	function tryAcquire(lockPath: string): boolean {
36	  try {
37	    const fd = openSync(lockPath, "wx");
38	    const payload: LockPayload = {
39	      pid: process.pid,
40	      createdAt: new Date().toISOString(),
41	    };
42	    writeSync(fd, JSON.stringify(payload));
43	    closeSync(fd);
44	    return true;
45	  } catch (err) {
46	    const code = (err as NodeJS.ErrnoException).code;
47	    if (code === "EEXIST") return false;
48	    if (code === "ENOENT") {
49	      mkdirSync(dirname(lockPath), { recursive: true });
50	      return tryAcquire(lockPath);
51	    }
52	    throw err;
53	  }
54	}
55	
56	function isStale(lockPath: string, staleMs: number): boolean {
57	  try {
58	    const raw = readFileSync(lockPath, "utf-8");
59	    const parsed = JSON.parse(raw) as LockPayload;
60	    const createdAt = Date.parse(parsed.createdAt);
61	    if (!Number.isFinite(createdAt)) return false;
62	    return Date.now() - createdAt > staleMs;
63	  } catch {
64	    return false;
65	  }
66	}
67	
68	function reclaim(lockPath: string): void {
69	  try {
70	    unlinkSync(lockPath);
71	  } catch (err) {
72	    const code = (err as NodeJS.ErrnoException).code;
73	    if (code !== "ENOENT") throw err;
74	  }
75	}
76	
77	function releaseLock(lockPath: string): void {
78	  try {
79	    unlinkSync(lockPath);
80	  } catch (err) {
81	    const code = (err as NodeJS.ErrnoException).code;
82	    if (code !== "ENOENT") throw err;
83	  }
84	}
85	
86	export async function withExclusiveLock<T>(
87	  lockPath: string,
88	  fn: () => Promise<T>,
89	  opts: LockOptions = {}
90	): Promise<T> {
91	  const { staleMs, retryMs, retries } = { ...DEFAULTS, ...opts };
92	
93	  for (let attempt = 0; attempt <= retries; attempt++) {
94	    if (tryAcquire(lockPath)) {
95	      try {
96	        return await fn();
97	      } finally {
98	        releaseLock(lockPath);
99	      }
100	    }
101	
102	    if (isStale(lockPath, staleMs)) {
103	      reclaim(lockPath);
104	      continue;
105	    }
106	
107	    if (attempt === retries) break;
108	    await new Promise((resolve) => setTimeout(resolve, retryMs));
109	  }
110	
111	  throw new LockBusyError(lockPath);
112	}
