1	/**
2	 * qmd CLI detection.
3	 *
4	 * qmd is an optional BM25 + vector search layer over markdown vaults. When
5	 * installed and the vault is registered as a collection, cairn workflows use
6	 * qmd_deep_search as the primary search step.
7	 */
8	
9	export function isQmdOnPath(): boolean {
10	  return !!Bun.which("qmd");
11	}
12	
13	export interface QmdCollection {
14	  name: string;
15	  path?: string;
16	}
17	
18	/**
19	 * List qmd collections. Returns null if qmd is not installed or the call
20	 * fails. Output parsing is best-effort — qmd output format may vary by
21	 * version.
22	 */
23	export async function listQmdCollections(): Promise<QmdCollection[] | null> {
24	  if (!isQmdOnPath()) return null;
25	
26	  try {
27	    const proc = Bun.spawn(["qmd", "collection", "list"], {
28	      stdout: "pipe",
29	      stderr: "ignore",
30	    });
31	    const output = await new Response(proc.stdout).text();
32	    const exitCode = await proc.exited;
33	    if (exitCode !== 0) return null;
34	
35	    const collections: QmdCollection[] = [];
36	    for (const line of output.split("\n")) {
37	      const trimmed = line.trim();
38	      if (!trimmed || trimmed.startsWith("#")) continue;
39	      const [name, ...rest] = trimmed.split(/\s+/);
40	      if (!name) continue;
41	      collections.push({ name, path: rest.join(" ") || undefined });
42	    }
43	    return collections;
44	  } catch {
45	    return null;
46	  }
47	}
48	
49	/**
50	 * Whether a vault path appears in the qmd collection list.
51	 */
52	export async function isVaultRegistered(vaultPath: string): Promise<boolean> {
53	  const collections = await listQmdCollections();
54	  if (!collections) return false;
55	  return collections.some((c) => c.path === vaultPath);
56	}
