58	export const QMD_INSTALL_HINT = `qmd is optional — install for hybrid BM25 + vector search:
59	
60	  npm install -g @tobilu/qmd
61	  qmd collection add <vault-path> --name cairn --mask "**/*.md"
62	  qmd embed
63	
64	Then add the MCP server to your Claude Code config:
65	
66	  { "mcpServers": { "qmd": { "command": "qmd", "args": ["mcp"] } } }
67	
68	See https://github.com/qntx-labs/qmd for details.`;
