8	
9	type Status = "ok" | "warn" | "error";
10	
11	const GLYPH: Record<Status, string> = {
12	  ok: "✓",
13	  warn: "!",
14	  error: "✗",
15	};
16	
17	function line(status: Status, label: string, detail?: string): string {
18	  const suffix = detail ? ` — ${detail}` : "";
19	  return `  ${GLYPH[status]} ${label}${suffix}`;
20	}
21	
22	export default defineCommand({
23	  meta: { name: "doctor", description: "Report cairn vault + dependency health" },
24	  args: {
25	    vaultPath: { type: "string", description: "Path to the vault directory", alias: ["p"] },
26	  },
27	  async run({ args }) {
28	    const vaultPath = args.vaultPath ?? resolveVaultPath(process.cwd());
29	    const lines: string[] = [];
30	    let warnings = 0;
31	    let errors = 0;
32	
33	    lines.push(`cairn doctor — v${VERSION}`);
34	    lines.push("");
35	    lines.push("Vault");
36	
37	    const state = checkVaultState(vaultPath);
38	    if (state === "cairn") {
39	      lines.push(line("ok", "vault initialized", vaultPath));
40	
41	      const statePath = join(vaultPath, ".cairn", "state.json");
42	      try {
43	        const parsed = JSON.parse(readFileSync(statePath, "utf-8"));
44	        lines.push(line("ok", "state.json readable", `created ${parsed.createdAt ?? "unknown"}`));
45	      } catch (err) {
46	        errors++;
47	        lines.push(line("error", "state.json unreadable", String(err)));
48	      }
49	
50	      const sessionsDir = join(vaultPath, "sessions");
51	      if (existsSync(sessionsDir)) {
52	        const newestMd = findNewestMarkdown(vaultPath);
53	        if (newestMd) {
54	          const days = Math.floor((Date.now() - newestMd.mtimeMs) / 86400000);
55	          lines.push(
56	            line(
57	              days > 30 ? "warn" : "ok",
58	              "newest wiki page",
59	              `${newestMd.path} (${days}d ago)`
60	            )
61	          );
62	          if (days > 30) warnings++;
63	        }
64	      }
65	    } else {
66	      errors++;
67	      lines.push(line("error", `vault state: ${state}`, `run 'cairn init' at ${vaultPath}`));
68	    }
69	
70	    lines.push("");
71	    lines.push("qmd (optional hybrid search)");
72	
73	    if (isQmdOnPath()) {
74	      lines.push(line("ok", "qmd binary on PATH"));
75	      const registered = await isVaultRegistered(vaultPath);
76	      if (registered) {
77	        lines.push(line("ok", "vault registered as qmd collection"));
78	      } else {
79	        warnings++;
80	        lines.push(
81	          line(
82	            "warn",
83	            "vault not registered",
84	            `run 'qmd collection add ${vaultPath} --name cairn --mask "**/*.md" && qmd embed'`
85	          )
86	        );
87	      }
88	    } else {
89	      warnings++;
90	      lines.push(line("warn", "qmd not installed", "hybrid search disabled, fallback to index.md walk"));
91	    }
92	
93	    lines.push("");
94	    lines.push("entire (session capture)");
95	
96	    if (await isEntireOnPath()) {
97	      lines.push(line("ok", "entire binary on PATH"));
98	    } else {
99	      lines.push(line("ok", "entire not installed", "optional, cairn falls back to summary-only sessions"));
100	    }
101	
102	    lines.push("");
103	    if (errors > 0) {
104	      lines.push(`${errors} error(s), ${warnings} warning(s). Fix errors first.`);
105	    } else if (warnings > 0) {
106	      lines.push(`${warnings} warning(s). Vault is usable; address warnings to unlock full functionality.`);
107	      if (!isQmdOnPath()) {
108	        lines.push("");
109	        lines.push(QMD_INSTALL_HINT);
110	      }
111	    } else {
112	      lines.push("All checks passed.");
113	    }
114	
115	    console.log(lines.join("\n"));
116	    if (errors > 0) process.exit(1);
117	  },
118	});
119	
120	function findNewestMarkdown(vaultPath: string): { path: string; mtimeMs: number } | null {
121	  const roots = ["wiki", "sessions"];
122	  let newest: { path: string; mtimeMs: number } | null = null;
123	  for (const root of roots) {
124	    const dir = join(vaultPath, root);
125	    if (!existsSync(dir)) continue;
126	    walkForMarkdown(dir, (file) => {
127	      const stat = statSync(file);
128	      if (!newest || stat.mtimeMs > newest.mtimeMs) {
129	        newest = { path: file.replace(`${vaultPath}/`, ""), mtimeMs: stat.mtimeMs };
130	      }
131	    });
132	  }
133	  return newest;
134	}
135	
136	function walkForMarkdown(dir: string, onFile: (file: string) => void): void {
137	  for (const entry of readdirSync(dir)) {
138	    if (entry.startsWith(".")) continue;
139	    const full = join(dir, entry);
140	    const stat = statSync(full);
141	    if (stat.isDirectory()) {
142	      walkForMarkdown(full, onFile);
143	    } else if (entry.endsWith(".md")) {
144	      onFile(full);
145	    }
146	  }
147	}
