      vaultPath,
      scope: "raw",
      filename: args.filename,
      approve: Boolean(args.approve),
      lines: args.lines ? Number(args.lines) : undefined,
      bytes: args.bytes ? Number(args.bytes) : undefined,
    });
  },
});

