import {
  appendFileSync,
  existsSync,
  mkdirSync,
  renameSync,
  statSync,
} from "node:fs";
import { dirname } from "node:path";
import { withExclusiveLock } from "./lockfile";

const DEFAULT_MAX_BYTES = 2 * 1024 * 1024;

function rotateIfNeeded(logPath: string, maxBytes: number): void {
  if (!existsSync(logPath)) return;
