    expect(stdout).toBe("");
    expect(stderr).toMatch(/invalid --lines|positive integer/i);
  });

  it("rejects --lines=0", async () => {
    const vault = makeVault();
    const { exitCode, stderr } = await run(vault, ["notes.md", "--approve", "--lines", "0"]);
    expect(exitCode).not.toBe(0);
    expect(stderr).toMatch(/invalid --lines|positive integer/i);
  });

