    const chunks: EnvelopeChunk[] = [];

    if (existsSync(indexPath)) {
      const body = readFileSync(indexPath, "utf-8");
      const lines = body.split("\n");
      const headingText = lines
        .map((line, i) => ({ line, i }))
        .filter(({ line }) => /^##\s+/.test(line))
        .map(({ line }) => line.replace(/^##\s+/, "").trim())
